module fsm
(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);
    // Define states
    parameter S0 = 4'b0000;
    parameter S1 = 4'b0001;
    parameter S2 = 4'b0010;
    parameter S3 = 4'b0011;
    parameter S4 = 4'b0100;
    parameter S5 = 4'b0101;
    parameter S6 = 4'b0110;
    parameter S7 = 4'b0111;
    parameter S8 = 4'b1000;
    // Define state register
    reg [3:0] state;
    reg [3:0] next_state;
    // Define match register
    reg match_reg;
    // Sequential logic block triggered on the positive edge of CLK or the negative edge of RST
    always @(posedge CLK or negedge RST) begin
        if (!RST) begin
            state <= S0;
            MATCH <= 1'b0;
        end else begin
            state <= next_state;
        end
    end
    // Combinational logic block triggered on the change of IN or state
    always @(IN or state) begin
        if (IN == 1'b1) begin
            case (state)
                S0: begin
                    next_state = S1;
                    match_reg = 1'b0;
                end
                S1: begin
                    next_state = S2;
                    match_reg = 1'b0;
                end
                S2: begin
                    next_state = S3;
                    match_reg = 1'b0;
                end
                S3: begin
                    next_state = S4;
                    match_reg = 1'b0;
                end
                S4: begin
                    next_state = S1;
                    match_reg = 1'b1;
                end
                S5: begin
                    next_state = S1;
                    match_reg = 1'b0;
                end
                S6: begin
                    next_state = S3;
                    match_reg = 1'b0;
                end
                S7: begin
                    next_state = S4;
                    match_reg = 1'b0;
                end
                S8: begin
                    next_state = S1;
                    match_reg = 1'b0;
                end
                default: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
            endcase
        end else begin
            case (state)
                S0: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S1: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S2: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S3: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                S4: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
                default: begin
                    next_state = S0;
                    match_reg = 1'b0;
                end
            endcase
        end
    end
    assign MATCH = match_reg;
endmodule
